### 5.2 Jenkins Pipeline

Jenkins 支持声明式 Pipeline：

```groovy
// Jenkinsfile
pipeline {
  agent any
  stages {
    stage('Install') {
      steps {
        sh 'npm ci'
      }
    }
    stage('Test') {
      steps {
        sh 'npm run lint'
        sh 'npm test'
      }
    }
    stage('Build') {
      steps {
        sh 'npm run build'
      }
    }
    stage('Deploy') {
      steps {
        sh 'scp -r dist user@server:/var/www/app'
      }
    }
  }
}
```

